VALUES
  ('elementary-6f0ba476-moex-00884', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「繁華擾攘的羅東鎮，藏著一條名為『浮崙巷』的小徑，巷名充滿文藝感。名稱取自於當地舊名『浮崙仔』， 由於該區地勢高，水患淹不到，遠看像是浮出水面的車輪而得名。隨著街區發展更迭，周邊發展出夜市和商 圈，浮崙巷『鬧中取靜』，只有在地人知道的捷徑，獨樹一格成為文藝風小巷。在地文史工作者說，浮崙巷 正是在地鄉土作家黃春明出生地，早期著作《鑼》便是起源於此。」 這則報導從那幾個面向介紹「浮崙巷」？', '["地名由來", "特產小吃", "街巷特色", "著名地標 在地名人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00885', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '下列何者屬於租稅行政罰？', '["撤銷登記", "罰金", "沒收", "拘役"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00886', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '現行稅捐稽徵法所稱相當擔保，係指相當於擔保稅款之擔保品，下列何者錯誤？', '["經中央銀行掛牌之外幣、上市或上櫃之有價證券，按八折計算", "易於變價、無產權糾紛且能足額清償之土地或已辦妥建物所有權登記之房屋亦可當擔保品", "銀行存款單摺，按存款本金額計值", "黃金，按市場價格計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00887', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列何者錯誤？', '["稅捐稽徵機關認定課徵租稅之構成要件事實時，應以實質經濟事實關係及其所生實質經濟利益之歸屬 與享有為依據", "租稅規避及課徵租稅構成要件事實之認定，稅捐稽徵機關就其事實有舉證之責任", "納稅義務人得在從事特定交易行為前，提供相關證明文件，向稅捐稽徵機關申請諮詢，稅捐稽徵機關 應於3個月內答覆", "納稅義務人基於獲得租稅利益，違背稅法之立法目的，濫用法律形式，規避租稅構成要件之該當，以 達成與交易常規相當之經濟效果，為租稅規避"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00888', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依據現行稅捐稽徵法之規定，法人、合夥或非法人團體解散清算時，清算人於分配賸餘財產前，應依法 按稅捐受清償之順序，繳清稅捐。清算人違反前項規定者，其未清繳之稅捐應由下列何者負擔繳納義務？', '["公司負責人或合夥組織之合夥人", "全體股東", "清算人", "非法人團體之負責人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00889', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，稅捐稽徵機關對逃漏下列那些稅捐涉有犯罪嫌疑之案件，得敘明事由，聲請當地司 法機關簽發搜索票後，會同當地警察或自治人員，進入藏置帳簿、文件或證物之處所，實施搜查？', '["所得稅、營業稅", "貨物稅、菸酒稅", "貨物稅、營業稅", "所得稅、遺產及贈與稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00890', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依據現行稅捐稽徵法之規定，下列有關強制執行之敘述何者錯誤？', '["納稅義務人應納稅捐，於繳納期間屆滿30日後仍未繳納者，由稅捐稽徵機關移送強制執行", "納稅義務人須繳納半數稅款並依法申請復查，才能暫緩移送強制執行", "納稅義務人依規定繳納半數稅額確有困難，經稅捐稽徵機關核准，提供相當擔保者，得暫緩移送強制 執行", "納稅義務人繳納半數稅額及提供相當擔保確有困難，但稅捐稽徵機關已就納稅義務人相當於復查決定 應納稅額之財產，通知有關機關，不得為移轉或設定他項權利者，得暫緩移送強制執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
