  ('elementary-6f0ba476-moex-00892', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，下列個人所得分類之敘述何者錯誤？', '["短期票券到期兌償金額超過首次發售價格部分為利息所得", "與證券商或銀行從事結構型商品交易之所得屬其他所得", "個人一時貿易之盈餘屬營利所得", "個人領取之資遣費為薪資所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00893', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，下列何種所得須依規定課徵所得稅？', '["依法經營不對外營業消費合作社之盈餘", "公務人員所領政府發給之特支費", "教育、文化、公益、慈善機關或團體，符合行政院規定標準者，其本身之所得及其附屬作業組織之所得", "取自營利事業贈與之財產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
